diff --git a/tests/issues/GH2774.test.ts b/tests/issues/GH2774.test.ts
new file mode 100644
index 0000000..b8328ac
--- /dev/null
+++ b/tests/issues/GH2774.test.ts
@@ -0,0 +1,59 @@
+import { Embeddable, Embedded, Entity, MikroORM, PrimaryKey, Property } from '@mikro-orm/core';
+
+@Embeddable()
+export class Nested {
+
+  @Property({ nullable: true })
+  value: string | null = null;
+
+}
+
+@Embeddable()
+export class Name {
+
+  @Property({ nullable: true })
+  value: string | null = null;
+
+  @Embedded()
+  nested!: Nested;
+
+}
+
+@Entity()
+export class User {
+
+  @PrimaryKey()
+  id!: number;
+
+  @Embedded()
+  name!: Name;
+
+}
+
+describe('GH issue 2774', () => {
+
+  let orm: MikroORM;
+
+  beforeAll(async () => {
+    orm = await MikroORM.init({
+      entities: [User, Name, Nested],
+      dbName: ':memory:',
+      type: 'sqlite',
+    });
+    await orm.getSchemaGenerator().createSchema();
+  });
+
+  afterAll(() => orm.close(true));
+
+  test('embeddable with only null values should be hydrated', async () => {
+    let user = new User();
+    user.name = new Name();
+    user.name.nested = new Nested();
+    await orm.em.persist(user).flush();
+
+    user = await orm.em.fork().findOneOrFail(User, user);
+    expect(user.name).toBeDefined();
+    expect(user.name.value).toBeNull();
+  });
+
+});

