+export const chainOrLogic = (
+  ...binaryExpressions: t.BinaryExpression[]
+): t.LogicalExpression | t.BinaryExpression => {
+  if (binaryExpressions.length === 1) {
+    return binaryExpressions[0]!;
+  }
+
